def somme(n):
    total = 0
    for i in range(1, n + 1):
        total += i
    return total

def inverser(liste):
    inversee = []
    for i in range(len(liste)):
        inversee.append(liste[-1-i])
    return inversee

def minimum(liste):
    mini = liste[0]
    for i in range(1, len(liste)):
        if liste[i] < mini:
            mini = liste[i]
    return mini

def indice_minimum(liste):
    imini = 0
    for i in range(1, len(liste)):
        if liste[i] < liste[imini]:
            imini = i
    return imini

def indices_zeros(liste):
    indices = []
    for i in range(len(liste)):
        if liste[i] == 0:
            indices.append(i)
    return indices

def elements_negatifs(liste):
    negatifs = []
    for x in liste:
        if x < 0:
            negatifs.append(x)
    return negatifs

